     2→import { AsyncLocalStorage } from 'async_hooks';
     3→
     4→import { ROLLBAR } from '@constants/common.constant';
     5→
     6→export interface RollbarOptions {
     7→	/**
     8→	 * Custom fields to be merged with other event-specific fields.
     9→	 * These fields are searchable in the Rollbar dashboard.
    10→	 *
    11→	 * @example
    12→	 * fields: { accountId: 123, clientName: 'accounts-ui' }
    13→	 */
    14→	fields?: Record<string, number | string | boolean>;
    15→
    16→	/**
    17→	 * Custom data to be merged with other event-specific data.
    18→	 * This can include any additional context or metadata for the event.
    19→	 *
    20→	 * @example
    21→	 * data: { sessionId: "abc123", failedConstraints: { email: ['email must be an email'] } }
    22→	 */
    23→	data?: Record<string, unknown>;
    24→
    25→	/**
    26→	 * A custom string to be added to Rollbar's default fingerprint.
    27→	 * This is useful for resolving issues with over-grouping of events.
    28→	 *
    29→	 * @example
    30→	 * fingerprintContext: "custom-fingerprint"
    31→	 */
    32→	fingerprintContext?: string;
    33→
    34→	/**
    35→	 * A custom title for the issue, which will appear in the Rollbar dashboard.
    36→	 *
    37→	 * @example
    38→	 * issueTitle: "Unexpected Error in Payment Processing"
    39→	 */
    40→	issueTitle?: string;
    41→
    42→	/**
    43→	 * A list of entity names. If a NotFoundError is caused by any of these entities,
    44→	 * the corresponding Rollbar event will be ignored and not logged.
    45→	 *
    46→	 * @example
    47→	 * notFoundErrorsIgnoredEntities: ["User", "Order"]
    48→	 */
    49→	notFoundErrorsIgnoredEntities?: string[];
    50→}
    51→
    52→export interface RequestStore {
    53→	rollbar: RollbarOptions | undefined;
    54→	[key: string]: unknown;
    55→}
    56→
    57→const defaultStoreValue: RequestStore = {
    58→	[ROLLBAR]: undefined,
    59→};
    60→
    61→export function deepClone<T>(obj: T): T {
    62→	if (obj === null || obj === undefined || typeof obj !== 'object') return obj;
    63→
    64→	const str = JSON.stringify(obj);
    65→	return JSON.parse(str) as T;
    66→}
    67→
    68→export function mergeObjectsDeeply<T extends Record<string, unknown>>(
    69→	target: T,
    70→	source: T,
    71→): T {
    72→	if (!target || typeof target !== 'object') {
    73→		return source;
    74→	}
    75→
    76→	if (!source || typeof source !== 'object') {
    77→		return target;
    78→	}
    79→
    80→	for (const key in source) {
    81→		if (source[key] && typeof source[key] === 'object') {
    82→			target[key] = mergeObjectsDeeply(target[key] || {}, source[key]) as T[Extract<
    83→				keyof T,
    84→				string
    85→			>];
    86→		} else {
    87→			target[key] = source[key];
    88→		}
    89→	}
    90→	return target;
    91→}
    92→
    93→export const requestStore = {
    94→	asyncLocalStorage: new AsyncLocalStorage<RequestStore>(),
    95→
    96→	set<T extends keyof RequestStore>(key: T, value: RequestStore[T]): void {
    97→		const currentStore = this.asyncLocalStorage.getStore();
    98→		if (currentStore) {
    99→			currentStore[key] = value;
   100→		} else {
   101→			this.asyncLocalStorage.enterWith({ ...defaultStoreValue, [key]: value });
   102→		}
   103→	},
   104→
   105→	getOrThrow<T extends keyof RequestStore>(key: T): RequestStore[T] {
   106→		const currentStore = this.getStoreOrThrow();
   107→		const value = currentStore[key];
   108→		if (!value) {
   109→			throw new Error(`Store value for key ${key} is not set`);
   110→		}
   111→		return value;
   112→	},
   113→
   114→	get<T extends keyof RequestStore>(key: T): RequestStore[T] {
   115→		const currentStore = this.asyncLocalStorage.getStore();
   116→		return currentStore?.[key];
   117→	},
   118→
   119→	update<T extends keyof RequestStore>(key: T, updates: Partial<RequestStore[T]>): void {
   120→		if (key !== ROLLBAR) {
   121→			throw new Error(`Key ${key} is not supported`);
   122→		}
   123→		const currentRollbar = deepClone(this.get(key)) ?? ({} as RollbarOptions);
   124→		const updatedRollbar = mergeObjectsDeeply(updates, currentRollbar) as RollbarOptions;
   125→		this.set('rollbar', updatedRollbar);
   126→	},
   127→
   128→	getStoreOrThrow(): RequestStore {
   129→		const currentStore = this.asyncLocalStorage.getStore();
   130→		if (!currentStore) {
   131→			throw new Error('Store is not initialized');
   132→		}
   133→		return currentStore;
   134→	},
   135→
   136→	initializeStore(initStoreValues: Partial<RequestStore> = {}): void {
   137→		this.asyncLocalStorage.enterWith({ ...defaultStoreValue, ...initStoreValues });
   138→	},
   139→
   140→	run(store: RequestStore, callback: () => void): void {
   141→		this.asyncLocalStorage.run(store, callback);
   142→	},
   143→};
