set<T extends keyof RequestStore>(key: T, value: RequestStore[T]): void {
	const currentStore = this.asyncLocalStorage.getStore();
	if (currentStore) {
		currentStore[key] = value;
	} else {
		this.asyncLocalStorage.enterWith({ ...defaultStoreValue, [key]: value });
	}
},

getOrThrow<T extends keyof RequestStore>(key: T): RequestStore[T] {
	const currentStore = this.getStoreOrThrow();
	const value = currentStore[key];
	if (!value) {
		throw new Error(`Store value for key ${key} is not set`);
	}
	return value;
},

get<T extends keyof RequestStore>(key: T): RequestStore[T] {
	const currentStore = this.asyncLocalStorage.getStore();
	return currentStore?.[key];
},

update<T extends keyof RequestStore>(key: T, updates: Partial<RequestStore[T]>): void {
	if (key !== ROLLBAR) {
		throw new Error(`Key ${key} is not supported`);
	}
	const currentRollbar = deepClone({ obj: this.get(key) }) ?? ({} as RollbarOptions);
	const updatedRollbar = mergeObjectsDeeply({ target: updates, source: currentRollbar }) as RollbarOptions;
	this.set('rollbar', updatedRollbar);
},

getStoreOrThrow(): RequestStore {
	const currentStore = this.asyncLocalStorage.getStore();
	if (!currentStore) {
		throw new Error('Store is not initialized');
	}
	return currentStore;
},

initializeStore(initStoreValues: Partial<RequestStore> = {}): void {
	this.asyncLocalStorage.enterWith({ ...defaultStoreValue, ...initStoreValues });
},

run(store: RequestStore, callback: () => void): void {
	this.asyncLocalStorage.run(store, callback);
},

