    64→	issueTitle: string;
    65→}): void {
    66→	if (isDataWithTraceChain({ data })) {
    67→		const dataWithTraceChain = data as dataWithTraceChain;
    68→		const firstException = dataWithTraceChain.body.trace_chain[0];
    69→		if (isObjectWithException({ data: firstException })) {
    70→			const firstExceptionWithMessage = firstException as objectWithException;
    71→			firstExceptionWithMessage.exception.message = issueTitle;
    72→		}
    73→	}
    74→}
    75→
    76→export function mergeFieldsAndData({
    77→	data,
    78→	rollbarOptions,
    79→}: {
    80→	data: Rollbar.Dictionary;
    81→	rollbarOptions: RollbarOptions;
    82→}): void {
    83→	data['custom'] = data['custom'] ?? {};
    84→	const custom = data['custom'] as Record<string, unknown>;
    85→	if (rollbarOptions.fields) {
    86→		Object.assign(custom, rollbarOptions.fields);
    87→	}
    88→
    89→	const fingerprint = rollbarOptions.fingerprintContext
    90→		? { fingerprintContext: rollbarOptions.fingerprintContext }
    91→		: undefined;
    92→	if (rollbarOptions.data || fingerprint) {
    93→		if (!custom['extraArgs'] || typeof custom['extraArgs'] !== 'object') {
    94→			custom['extraArgs'] = {};
    95→		}
    96→		Object.assign(
    97→			custom['extraArgs'] as Record<string, unknown>,
    98→			rollbarOptions.data,
    99→			fingerprint,
   100→		);
   101→	}
   102→}
   103→
   104→export function isDataWithTraceChain({ data }: { data: Rollbar.Dictionary }): boolean {
   105→	return (
   106→		'body' in data &&
   107→		typeof data['body'] === 'object' &&
   108→		data['body'] !== null &&
   109→		'trace_chain' in data['body'] &&
   110→		Array.isArray(data['body'].trace_chain)
   111→	);
   112→}
   113→
   114→export function isObjectWithException({ data }: { data: unknown }): boolean {
   115→	return (
   116→		typeof data === 'object' &&
   117→		data !== null &&
   118→		'exception' in data &&
   119→		typeof data.exception === 'object' &&
   120→		data.exception !== null &&
   121→		'message' in data.exception
   122→	);
   123→}
