import { AsyncLocalStorage } from 'async_hooks';

import {
	requestStore,
	deepClone,
	mergeObjectsDeeply,
	RequestStore,
} from '@utils/request-store.util';

import { ROLLBAR } from '@constants/common.constant';

jest.mock('async_hooks', () => ({
	AsyncLocalStorage: jest.fn().mockImplementation(() => ({
		enterWith: jest.fn(),
		getStore: jest.fn(),
		run: jest.fn((_store, callback: () => void) => {
			callback();
		}),
	})),
}));
const getStoreSpy = jest.spyOn(requestStore.asyncLocalStorage, 'getStore');
const enterWithSpy = jest.spyOn(requestStore.asyncLocalStorage, 'enterWith');
const runSpy = jest.spyOn(requestStore.asyncLocalStorage, 'run');

describe('request-store.util', () => {
	let mockAsyncLocalStorage: jest.Mocked<AsyncLocalStorage<RequestStore>>;

	beforeEach(() => {
		jest.clearAllMocks();
		mockAsyncLocalStorage = requestStore.asyncLocalStorage as jest.Mocked<
			AsyncLocalStorage<RequestStore>
		>;
	});

	describe('deepClone', () => {
		it('should return primitives as is', () => {
			expect(deepClone({ obj: null })).toBeNull();
			expect(deepClone({ obj: 123 })).toBe(123);
			expect(deepClone({ obj: 'test' })).toBe('test');
			expect(deepClone({ obj: true })).toBe(true);
		});

		it('should create a deep clone of an object', () => {
			const original = { a: 1, b: { c: 2 } };
			const clone = deepClone({ obj: original });

			expect(clone).toEqual(original);
			expect(clone).not.toBe(original);
			expect(clone.b).not.toBe(original.b);
		});
	});

	describe('mergeObjectsDeeply', () => {
		it('should return source if target is not an object', () => {
			const source = { a: 1 };
			// @ts-ignore
			expect(mergeObjectsDeeply({ target: null, source })).toBe(source);
			// @ts-ignore
			expect(mergeObjectsDeeply({ target: undefined, source })).toBe(source);
			// @ts-ignore
			expect(mergeObjectsDeeply({ target: 123, source })).toBe(source);
		});

		it('should return target if source is not an object', () => {
			const target = { a: 1 };
			// @ts-ignore
			expect(mergeObjectsDeeply({ target, source: null })).toBe(target);
			// @ts-ignore
			expect(mergeObjectsDeeply({ target, source: undefined })).toBe(target);
			// @ts-ignore
			expect(mergeObjectsDeeply({ target, source: 123 })).toBe(target);
		});

		it('should merge objects deeply', () => {
			const target = { a: 1, b: { c: 2, d: 3 } };
			const source = { b: { c: 4, e: 5 }, f: 6 };

			// @ts-ignore
			const result = mergeObjectsDeeply({ target, source });

			expect(result).toEqual({
				a: 1,
				b: { c: 4, d: 3, e: 5 },
				f: 6,
			});
			expect(result).toBe(target);
		});
	});

